link.script:
  window.dataLayer = window.dataLayer || [];
  function gtag(){dataLayer.push(arguments);}
  gtag('js', new Date());

  gtag('config', 'G-BXY69GDH8Q');

window.addEventListener('DOMContentLoaded', function() {
        const isLogin = '0';
        let site_key = '6LeNtyIpAAAAABRFwVzJhbs6GeAo22Jy87OH57YF';
        let ajax_url = 'https://fpt-is.com/wp-admin/admin-ajax.php';
        jQuery(document).ready(function($) {
            if ($('#logout').length) {
                $('#logout').on('click', function() {
                    let site_key = '6LeNtyIpAAAAABRFwVzJhbs6GeAo22Jy87OH57YF';
                    grecaptcha.ready(function() {
                        grecaptcha.execute(site_key, {
                            action: 'logout_capcha'
                        }).then(function(token) {
                            $.post(
                                "https://fpt-is.com/wp-admin/admin-ajax.php", {
                                    action: 'logout',
                                    action1: 'logout_capcha',
                                    token1: token
                                },
                                function(data) {
                                    if (data.status == 1) {
                                        window.location.reload();
                                    }
                                }, "json");
                            return false;
                        });
                    });
                });
            }
            if ($('#form-register-document').length) {
                $('#form-register-document').submit(function(e) {
                    e.preventDefault();
                    let site_key = '6LeNtyIpAAAAABRFwVzJhbs6GeAo22Jy87OH57YF';
                    let csrfToken = $('#form-register-document input[name="csrfToken"]').val();
                    let topic = [];
                    $('input[name="topic\[\]"]').each(function() {
                        if ($(this).prop('checked')) {
                            topic.push($(this).val());
                        }
                    });
                    if (topic.length > 0) {
                        grecaptcha.ready(function() {
                            grecaptcha.execute(site_key, {
                                action: 'register_document_capcha'
                            }).then(function(token) {
                                $.ajax({
                                    type: 'post',
                                    dataType: 'json',
                                    cache: false,
                                    url: 'https://fpt-is.com/wp-admin/admin-ajax.php',
                                    data: {
                                        topic: JSON.stringify(topic),
                                        nonce: csrfToken,
                                        action: 'registerDocuments',
                                        action1: 'register_document_capcha',
                                        token1: token
                                    },
                                    beforeSend: function() {
                                        $('#form-register-document button').css('opacity', '0.3');
                                    },
                                    success: function(response) {
                                        $('#form-register-document button').css('opacity', '1');
                                        if (response.status == 1) {
                                            $('#form__popup-document').modal('hide');
                                            Swal.fire({
                                                icon: 'success',
                                                text: response.mess,
                                            });
                                        } else {
                                            Swal.fire({
                                                icon: 'error',
                                                text: response.mess,
                                            });
                                        }
                                    }
                                });
                                return false;
                            });
                        });
                    } else {
                        Swal.fire({
                            icon: 'error',
                            text: 'Vui lòng chọn tin và chủ đề bạn muốn theo dõi.',
                        });
                    }
                });
            }
            function downloadDocuments() {
                // let site_key = '6LeNtyIpAAAAABRFwVzJhbs6GeAo22Jy87OH57YF';
                let url = $('.download-documents').attr('data-url');
                if($('.download-documents').length > 0) {
                    grecaptcha.ready(function() {
                        grecaptcha.execute(site_key, {action: 'download_documents_capcha'}).then(function(token) {
                            $.ajax({
                                type: 'post',
                                dataType: 'json',
                                cache: false,
                                url: ajax_url,
                                data: {
                                    url: url,
                                    action: 'downloadDocuments',
                                    action1: 'download_documents_capcha',
                                    token1: token
                                },
                                beforeSend:function () {
                                    $('.download-documents').css('opacity', '0.3');
                                },
                                success: function(response) {
                                    $('.download-documents').css('opacity', '1');
                                    if(response.status == 1) {
                                        fetch(response.url)
                                            .then(response => response.blob())
                                            .then(blob => {
                                                const url = URL.createObjectURL(blob);
                                                const a = document.createElement('a');
                                                a.href = url;
                                                a.download = response.name;
                                                a.click();
                                                URL.revokeObjectURL(url);
                                            })
                                            .catch(error => {
                                                console.error('File download failed:', error);
                                            });
                                        $('.swal2-confirm').click();
                                        setTimeout(function () {
                                            if(isLogin === '1') {
                                                $('#form__popup-document').modal('show');
                                            } else {
                                                $('#modal-register').modal('show');
                                            }
                                        }, 3000)
                                    } else {
                                        Swal.fire({
                                            icon: 'error',
                                            text: response.mess,
                                        });
                                    }
                                }
                            });
                            return false;
                        });
                    });
                }
            }
            // submit contactform
            var wpcf7Elm = document.querySelector( '#form__popup-register-document form' );
            wpcf7Elm.addEventListener( 'wpcf7submit', function( event ) {
                $('#form__popup-register-document').modal('hide');
                // $('.download-documents').click();
                downloadDocuments();
            }, false );
            if($('.download-documents').length) {
                $('.download-documents').on('click', function (e) {
                    e.preventDefault();
                    if(isLogin === '1') {
                        downloadDocuments();
                    }
                });
            }
        });
    });

body.script:
